        if(v[i].first % 2 == v[i].second % 2 &amp;&amp; y) {
            ans += v[i].first - pre - 1;
            y = !y;
            pre = v[i].first;
            continue;
        }
        if(v[i].first % 2 == v[i].second % 2 &amp;&amp; !y) {
            ans += v[i].first - pre;
            pre = v[i].first;
            continue;
        }
        if(v[i].first % 2 != v[i].second % 2 &amp;&amp; y) {
            ans += v[i].first - pre;
            pre = v[i].first;
