如果没有奇数的，输出0；否则，先把所有偶数相加，加上最大的奇数，再在剩下的奇数中选一半的最大的数。
void solve() {
    int n; cin &gt;&gt; n;
    vi v(n + 5);
    for(int i = 1; i &lt;= n;++ i) {
        cin &gt;&gt; v[i];
    }
    vi ji;
    vi ou;
    int sum = 0;
    for(int i = 1; i &lt;= n; ++ i) {
        if(v[i] % 2 == 0) {
            ou.push_back(v[i]);
            sum += v[i];
        } else {
            ji.push_back(v[i]);
        }
    }
    if(sz(ji) == 0) {
        cout &lt;&lt; 0 &lt;&lt; "\n";
    } else {
        sort(all(ji), greater&lt;int&gt;());
        sum += ji[0];
        for(int i = 1; i &lt;= (sz(ji) - 1) / 2; ++ i)
            sum += ji[i];
        cout &lt;&lt; sum &lt;&lt; "\n";
    }
}
