真的要哭死了，赛时的unordered_map过了，赛后超时了，真的以后把unordered_map给禁了，map随便用。
双指针，先找出所有元素数量小于等于 kkk 的合法区间的数量，再找出元素数量小于 kkk  的合法区间数量，减去之后，就是元素数量等于 kkk 的合法区间数量。
void solve() {
    int n, k, L, R; cin &gt;&gt; n &gt;&gt; k &gt;&gt; L &gt;&gt; R;
    vi v(n);
    for(int i = 0; i &lt; n; ++ i) cin &gt;&gt; v[i];

    map&lt;int,int&gt; cnt;
    int d = 0;
    int l = 0;
    int ans1 = 0;

    for (int r = 0; r &lt; n; r++) {
        cnt[v[r]]++;
        if (cnt[v[r]] == 1) d++;

        while (d &gt; k) {
            cnt[v[l]]--;
            if (cnt[v[l]] == 0) d--;
            l++;
        }

        int minl = max(l, r - R + 1);
        int maxl = r - L + 1;
        if (maxl &gt;= minl) {
            ans1 += (ll)(maxl - minl + 1);
        }
    }
    map&lt;int,int&gt; cnt1;
    d = 0;
    l = 0;
    int ans2 = 0;
    k --;
    for (int r = 0; r &lt; n; r++) {
        cnt1[v[r]]++;
        if (cnt1[v[r]] == 1) d++;

        while (d &gt; k) {
            cnt1[v[l]]--;
            if (cnt1[v[l]] == 0) d--;
            l++;
        }

        int minl = max(l, r - R + 1);
        int maxl = r - L + 1;
        if (maxl &gt;= minl) {
            ans2 += (ll)(maxl - minl + 1);
        }
    }
    cout &lt;&lt; ans1 - ans2 &lt;&lt; "\n";
}
