}
 C
将较小的数指向较大的数，形成一张图，然后拓扑排序
具体来说：
if(x&gt;y):v→uif (x &gt; y) : v \to u
if(x&gt;y):v→u
else:u→velse: u \to v
else:u→v
构成一张图，对拓扑序的每一个元素表示的位置依次递增
void solve() {
    int n; cin &gt;&gt; n;
    vvi G(n + 5);
    vi din(n + 5), tp;

    for(int i = 0; i &lt; n - 1; ++ i) {
        int u, v, x, y;
        cin &gt;&gt; u &gt;&gt; v &gt;&gt; x &gt;&gt; y;
        if(x &gt; y) {
            G[v].push_back(u);
            din[u] ++;
        } else {
            G[u].push_back(v);
            din[v] ++;
        }
    }

    function&lt;void()&gt; toposort = [&amp;]() {
        queue&lt;int&gt; q;
        for(int i=1;i&lt;=n;++i) 
            if(din[i]==0) q.push(i);
        while(!q.empty()) {
            int x = q.front();
            q.pop();
            tp.push_back(x);
            for(auto c : G[x]) 
                if(--din[c] == 0) q.push(c);
        }
        return tp.size() == n;
    };

    toposort();

    int idx = 1;
    vi ans(n + 5);
    for(int i: tp) 
        ans[i] = idx ++;

    for(int i = 1; i &lt;= n ;++ i) 
       cout &lt;&lt; ans[i] &lt;&lt; " \n"[i == n];
}

