将排列中没出现过的数从大到小填到0的位置，再左右两边向中间缩，排好序的就缩，直到第一个未排序的地方，输出差。
void solve() {
    int n; cin &gt;&gt; n;
    vi v(n);
    map&lt;int, int&gt; mp;
    for(int i = 0; i &lt; n; ++ i) {
        cin &gt;&gt; v[i];
        mp[v[i]] ++;
    }
    vi nums;
    for(int i = n; i &gt;= 1; -- i) {
        if(mp[i] == 0) nums.pb(i);
    }
    int pos = 0;
    for(int i = 0; i &lt; n; ++ i) {
        if(v[i] == 0) v[i] = nums[pos ++];
    }

    int l = 0, r = n - 1;
    for(int i = 0; i &lt; n; ++ i) {
        if(v[i] == i + 1) l ++;
        else break;
    }
    for(int i = n - 1; i &gt; 0; -- i) {
        if(v[i] == i + 1) r --;
        else break;
    }
    if(r - l + 1 &lt;= 0) cout &lt;&lt; 0 &lt;&lt; "\n";
    else  cout &lt;&lt; r - l + 1 &lt;&lt; '\n';
}
 C
dp，只有四种可能的转移
void solve() {
    int n; cin &gt;&gt; n;
    vi a(n), b(n);
    for(int i = 0; i &lt; n; ++ i) cin &gt;&gt; a[i];
    for(int i = 0; i &lt; n; ++ i) cin &gt;&gt; b[i];

    vi dp(2, 0), cur(2, 0);
    dp[0] = 1; dp[1] = 1; 
    for(int i = 1; i &lt; n; ++ i){
        cur[0] = cur[1] = 0;
        for(int j = 0; j &lt;= 1; ++ j){
            for(int k = 0; k &lt;= 1; ++ k){
                int p = (j == 0 ? a[i-1] : b[i-1]);
                int pp = (j == 0 ? b[i-1] : a[i-1]);
                int c = (k == 0 ? a[i] : b[i]);
                int cc = (k == 0 ? b[i] : a[i]);
                if(p &lt;= c &amp;&amp; pp &lt;= cc){
                    cur[k] += dp[j];
                    if(cur[k] &gt;= MOD) 
                        cur[k] -= MOD;
                }
            }
        }
        dp = cur;
    }
    int ans = 0;
    if(n == 1) ans += 2 % MOD; 
    else {
        dp[0] += dp[1];
        if(dp[0] &gt;= MOD) dp[0] -= MOD;
        ans += dp[0];
    }
    cout &lt;&lt; ans &lt;&lt; '\n';
}

