#include &lt;bits/stdc++.h&gt;
using namespace std;
using ll = long long; // long long的简写

ll prefix[1005][1005]; // 差分数组，可能会爆int，需要long long
int main() {
    int N, M, C;
    cin &gt;&gt; N &gt;&gt; M &gt;&gt; C;
    int num = 0;

    for(int i = 1; i &lt;= N; ++ i) {
        for(int j = 1; j &lt;= M; ++ j) {
            cin &gt;&gt; num;
            prefix[i][j] = prefix[i - 1][j] + prefix[i][j - 1]  - prefix[i - 1][j - 1] + num; 
            // 处理二维前缀和
        }
    }

    ll ans = 0; // 同样可能爆int
    int x = 0, y = 0;
    for(int i = C; i &lt;= N; ++ i) {
        for(int j = C; j &lt;= M; ++ j) {
            ll res = prefix[i][j] - prefix[i - C][j] - prefix[i][j - C] + prefix[i - C][j - C];
            if(res &gt; ans) {
                ans = res; // 计算最大值
                x = i - C + 1; // 记录坐标
                y = j - C + 1;
            }
        }
    }
    cout &lt;&lt; x &lt;&lt; " " &lt;&lt; y &lt;&lt; "\n"; // 输出坐标

    return 0;   
}
