const int N = 2e5 + 5;
class MS {
private:
    int b[N];
public:
    int ans = 0; // 求逆序对
    void msort(int l,int r, vector&lt;int&gt; &amp;arr){
        if(l &gt;= r) return;
        int mid = (l + r) &gt;&gt; 1;
        msort(l, mid, arr);
        msort(mid + 1,r,arr);
        int i = l, j = mid + 1, k = l;
        while(i &lt;= mid &amp;&amp; j &lt;= r) {
            if(arr[i] &lt;= arr[j]) b[k++] = arr[i++];
            else { b[k++] = arr[j++]; ans += mid - i + 1; }
        }
        while(i &lt;= mid) b[k++] = arr[i++];
        while(j &lt;= r) b[k++] = arr[j++];
        for(int i = l; i &lt;= r; ++i) arr[i] = b[i];
    }
};
