 马拉车算法
const int N = 2e7 + 5;
char a[N];
char s[N &lt;&lt; 1];
int d[N &lt;&lt; 1];
// scanf("%s", a + 1);
int manacher(char *a) {
    int n = strlen(a + 1), k = 0;
    s[0] = '$', s[++k] = '#';
    for(int i = 1; i &lt;= n; ++ i) {
        s[++k] = a[i];
        s[++k] = '#';
    }
    n = k, d[1] = 1;
    for(int i = 2, l, r = 1; i &lt;= n; ++ i) {
        if(i &lt;= r) d[i] = min(d[r-i+l], r-i+1);
        while(s[i-d[i]] == s[i+d[i]]) d[i]++;
        if(i + d[i] - 1 &gt; r) {
            l = i - d[i] + 1;
            r = i + d[i] - 1;
        }
    }
    return *max_element(d, d + n) - 1;
}
void solve() {  
    scanf("%s", a+1);
    cout &lt;&lt; manacher(a);
}
