void update(int p, int x, int k) {
    if(tr[p].l == x &amp;&amp; tr[p].r == x) {
        tr[p].sum = k;
        return;
    }
    int m = (tr[p].l + tr[p].r) &gt;&gt; 1;
    if(x &lt;= m) update(lc, x, k);
    if(x &gt; m)  update(rc, x, k);
    tr[p].sum = tr[lc].sum + tr[rc].sum;
}
