// 并查集
class DSU {
private:
    int par[N],rk[N];
public:
    // 初始化n个元素
    void init(int n) {
        for(int i = 1;i &lt;= n;++i) par[i] = i, rk[i] = 0;
    }
    // 查询树的根 (路径压缩)
    int find(int x) {
        return par[x] = par[x] == x ? x : find(par[x]);
    }
    // 普通合并
    int unite(int x, int y) {
        x = find(x);y = find(y);
        return x == y ? 0 : par[x] = y;
    }
    // 按秩合并
    void merge(int x, int y) {
        x = find(x);y = find(y);
        if(x == y) return;
        if(rk[x] &gt; rk[y]) swap(x, y);
        par[x] = y;
        if(rk[x] == rk[y]) rk[y]++;
    }
    // 判断x和y是否联通
    bool same(int x, int y) {
        return find(x) == find(y);
    }
};
// 最小生成树 kruskal算法
class MST : DSU {
private:
    struct edge{
        int u, v, cost;
        bool operator&lt;(const edge&amp; other) const {
            return cost &lt; other.cost; // 按权值升序排序
        }
    };
    vector&lt;edge&gt; es; // 边集
    vector&lt;edge&gt; mst; //最小生成树边集
    int V, res; //V:点数 res:MST各边长之和
public:
    MST(int n) : V(n) {} // 构造函数, 赋值V为n
    int kruskal() {
        sort(es.begin(), es.end());
        init(V);
        mst.clear();
        res =  0;
        for(auto &amp;e : es) {
            if(!same(e.u, e.v)) {
                unite(e.u, e.v);
                mst.push_back(e);
                res += e.cost;
            }
        }
        return res;
    }
    // 加边, 权
    void addedge(int u, int v, int cost) {
        es.push_back({u, v, cost});
    }
    // 判断是否连通, 先要使用kruskal算法
    bool isConnected() {
        set&lt;int&gt; st;
        for (int i = 1; i &lt;= V; ++i) {
            st.insert(find(i));
        }
        return st.size() == 1;
    }
};
