C++ 代码求欧拉函数，使用试除法，时间复杂度 O(n)O(\sqrt{n})O(n​)
int get_phi(int n) {
    int res = n;
    for(int i = 2; i * i &lt;= n; ++ i) {
        if(n % i == 0) {
            res = res / i * (i - 1);
            while(n % i == 0) n /= i;
        }
    }
    if(n &gt; 1) res = res / n * (n - 1);
    return res;
}
