当 bbb 小的时候，不用降幂，直接跑快速幂。
当 bbb 是大数时，先降幂，再跑快速幂。
扩展欧拉定理降幂
int depow(int phi, string s) {
    int b = 0, flag = 0;
    for(auto i: s) {
        b = b * 10 + (i - '0');
        if(b &gt;= phi) {
            flag = 1;
            b %= phi;
        }
    }
    if(flag) b += phi;
    return b;
}

int qpow(ll a, string s, ll mod) {
    ll res = 1;
    int b = depow(get_phi(mod), s);
    while (b) {
        if (b &amp; 1) res = res * a % mod;
        a = a * a % mod;
        b &gt;&gt;= 1;
    }
    return res;
}
